import sharp from 'sharp';
import type { Thumbnailer } from './config';

const MAX_WIDTH = 240;
const MAX_HEIGHT = 360;
const JPEG_QUALITY = 82;

const PLACEHOLDER_THUMBNAIL = Buffer.from(
  '',
  'base64',
);

/**
 * Sharp-based thumbnail encoder. Returns a JPEG Buffer fitting inside
 * MAX_WIDTH x MAX_HEIGHT, never upscaling. Failures fall back to a tiny
 * placeholder so the UI never sees a 500.
 */
export const sharpThumbnailer: Thumbnailer = async (source) => {
  if (!source || source.length === 0) return PLACEHOLDER_THUMBNAIL;
  try {
    const out = await sharp(source)
      .resize({
        width: MAX_WIDTH,
        height: MAX_HEIGHT,
        fit: 'inside',
        withoutEnlargement: true,
      })
      .jpeg({ quality: JPEG_QUALITY })
      .toBuffer();
    return out.length > 0 ? out : PLACEHOLDER_THUMBNAIL;
  } catch {
    return PLACEHOLDER_THUMBNAIL;
  }
};
